import { useState } from 'react';
import { Search, ChevronDown } from 'lucide-react';
import { Routes, Route, Link, useNavigate } from 'react-router-dom';
import './App.css';
import HomePage from './HomePage';
import AllTemplatesPage from './AllTemplatesPage';
import AllFeaturesPage from './AllFeaturesPage';
import AIFeaturesPage from './AIFeaturesPage';
import ServiceManagementPage from './ServiceManagementPage';
import MarketingPage from './MarketingPage';
import OperationsPage from './OperationsPage';
import SoftwareDevelopmentPage from './SoftwareDevelopmentPage';
import ITOperationsPage from './ITOperationsPage';
import HRTemplatesPage from './HRTemplatesPage';
import ScrumBoardPage from './ScrumBoardPage';
import ScrumTemplateInfoPage from './ScrumTemplateInfoPage';
import AgileFlowPage from './pages/AgileFlowPage';

function App() {
  const [showTemplatesDropdown, setShowTemplatesDropdown] = useState(false);
  const [showFeaturesDropdown, setShowFeaturesDropdown] = useState(false);

  return (
    <div className="container">
      {/* Navigation Bar */}
      <nav className="navbar">
        <div className="nav-left">
          <Link to="/" className="logo nav-logo-link">
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
              <path d="M12.03 2.01L2.83995 7.37L12.0299 12.69L21.1699 7.37L12.0299 2.01H12.03ZM3.78995 16.59L12.0299 21.36L20.2699 16.59L12.0299 11.82L3.78995 16.59Z" fill="#0052CC" />
              <path d="M12.03 2.01L2.83995 7.37L12.0299 12.69L21.1699 7.37L12.0299 2.01H12.03Z" fill="#2684FF" />
              <path d="M11.53 12.22L2.59995 17.58L11.53 22.94L20.46 17.58L11.53 12.22Z" fill="#0052CC" />
            </svg>
            <span className="brand-name">ANORYX</span>
          </Link>
          <ul className="nav-links">
            <li
              className="nav-item-dropdown"
              onMouseEnter={() => setShowFeaturesDropdown(true)}
              onMouseLeave={() => setShowFeaturesDropdown(false)}
              onClick={() => setShowFeaturesDropdown(!showFeaturesDropdown)}
            >
              Features <ChevronDown size={14} />
              {showFeaturesDropdown && (
                <div className="dropdown-menu shadow-lg" style={{ left: 0 }}>
                  <ul className="dropdown-list">
                    <li>
                      <Link to="/features">All Features</Link>
                    </li>
                    <li>
                      <Link to="/ai-features">AI Features</Link>
                    </li>
                  </ul>
                </div>
              )}
            </li>
            <li>Solutions <ChevronDown size={14} /></li>
            <li>Guide</li>
            <li
              className="nav-item-dropdown"
              onMouseEnter={() => setShowTemplatesDropdown(true)}
              onMouseLeave={() => setShowTemplatesDropdown(false)}
              onClick={() => setShowTemplatesDropdown(!showTemplatesDropdown)}
            >
              Templates <ChevronDown size={14} />
              {showTemplatesDropdown && (
                <div className="dropdown-menu shadow-lg">
                  <ul className="dropdown-list">
                    <li><Link to="/software-development" style={{ color: 'inherit', textDecoration: 'none' }}>Software Development</Link></li>
                    <li><Link to="/marketing" style={{ color: 'inherit', textDecoration: 'none' }}>Marketing</Link></li>
                    <li><Link to="/operations" style={{ color: 'inherit', textDecoration: 'none' }}>Operations</Link></li>
                    <li><Link to="/service-management" style={{ color: 'inherit', textDecoration: 'none' }}>Service Management</Link></li>
                    <li><Link to="/hr" style={{ color: 'inherit', textDecoration: 'none' }}>HR</Link></li>
                    <li><Link to="/it-operations" style={{ color: 'inherit', textDecoration: 'none' }}>IT Operations</Link></li>
                  </ul>
                </div>
              )}
            </li>
            <li>Pricing</li>
          </ul>
        </div>
        <div className="nav-right">
          <button className="btn-primary-outline">Get it free</button>
          <Search size={20} className="search-icon" />
          <span className="signin-link">Sign in</span>
        </div>
      </nav>

      {/* Route Definitions */}
      <Routes>
        <Route path="/" element={<HomePage />} />
        <Route path="/features" element={<AllFeaturesPage />} />
        <Route path="/marketing" element={<MarketingPage />} />
        <Route path="/operations" element={<OperationsPage />} />
        <Route path="/service-management" element={<ServiceManagementPage />} />
        <Route path="/ai-features" element={<AIFeaturesPage />} />
        <Route path="/templates" element={<AllTemplatesPage />} />
        <Route path="/software-development" element={<SoftwareDevelopmentPage />} />
        <Route path="/scrum-template" element={<ScrumTemplateInfoPage />} />
        <Route path="/scrum-board" element={<ScrumBoardPage />} />
        <Route path="/it-operations" element={<ITOperationsPage />} />
        <Route path="/hr" element={<HRTemplatesPage />} />
        <Route path="/agileflow" element={<AgileFlowPage />} />
      </Routes>
    </div>
  );
}

export default App;

import React, { useState, useEffect } from 'react';
import './MarketingPage.css';
import MarketingHero from './components/MarketingHero';

const MarketingPage = () => {
    const [text, setText] = useState('');
    const fullText = "MARKETING TEMPLATES";
    const [showCursor, setShowCursor] = useState(true);

    useEffect(() => {
        let i = 0;
        const typingInterval = setInterval(() => {
            setText(fullText.slice(0, i + 1));
            i++;
            if (i >= fullText.length) {
                clearInterval(typingInterval);
            }
        }, 75);

        return () => clearInterval(typingInterval);
    }, []);

    useEffect(() => {
        const cursorInterval = setInterval(() => {
            setShowCursor((prev) => !prev);
        }, 500);
        return () => clearInterval(cursorInterval);
    }, []);

    return (
        <div className="mkt-page">
            <MarketingHero />

            <div className="mkt-features-grid">
                {/* Row 1: Project Management */}
                <div className="mkt-feature-info">
                    <h2 className="mkt-feature-title">PROJECT MANAGEMENT TEMPLATE</h2>
                    <p className="mkt-feature-text mkt-typing-text">
                        {"Project management templates provide a structured framework to plan, organize, and track projects efficiently. They help teams standardize workflows, save time, and improve collaboration by offering ready-to-use formats for managing tasks, timelines, and resources.".split(' ').map((word, index) => (
                            <React.Fragment key={index}>
                                <span className="styled-word" style={{ animationDelay: `${index * 0.1}s` }}>
                                    {word}
                                </span>
                                {' '}
                            </React.Fragment>
                        ))}
                    </p>
                </div>
                <div className="mkt-feature-image-wrapper">
                    <img src="/images/marketing-project-management.png" alt="Project Management Timeline Dashboard" className="sd-feature-image" />
                </div>

                {/* Row 2: Marketing Service Management */}
                <div className="mkt-feature-info">
                    <h2 className="mkt-feature-title">MARKETING SERVICE MANAGEMENT TEMPLATE</h2>
                    <p className="mkt-feature-text mkt-typing-text">
                        {"Marketing Service Management template provides a structured framework to manage campaigns, requests, and performance tracking efficiently. It helps teams improve collaboration, optimize marketing efforts, and achieve measurable business growth.".split(' ').map((word, index) => (
                            <React.Fragment key={index}>
                                <span className="styled-word" style={{ animationDelay: `${index * 0.1}s` }}>
                                    {word}
                                </span>
                                {' '}
                            </React.Fragment>
                        ))}
                    </p>
                </div>
                <div className="mkt-feature-image-wrapper">
                    <img src="/images/marketing-service-management.png" alt="Marketing Service Management Dashboard" className="sd-feature-image" />
                </div>

                {/* Row 3: Content Management */}
                <div className="mkt-feature-info">
                    <h2 className="mkt-feature-title">CONTENT MANAGEMENT TEMPLATE</h2>
                    <p className="mkt-feature-text mkt-typing-text">
                        {"A Content Management template provides a structured framework to plan, create, publish, and optimize content efficiently. It helps teams maintain consistency, improve collaboration, and maximize content performance across platforms.".split(' ').map((word, index) => (
                            <React.Fragment key={index}>
                                <span className="styled-word" style={{ animationDelay: `${index * 0.1}s` }}>
                                    {word}
                                </span>
                                {' '}
                            </React.Fragment>
                        ))}
                    </p>
                </div>
                <div className="mkt-feature-image-wrapper">
                    <img src="/images/marketing-content-management.png" alt="Content Management Dashboard" className="sd-feature-image" />
                </div>
            </div>
        </div>
    );
};

export default MarketingPage;

import React, { useState } from 'react';
import './ScrumBoardPage.css';

const initialColumns = {
    'todo': {
        name: 'To Do',
        items: [
            { id: '1', content: 'Create project roadmap', assignee: 'SM', type: 'story' },
            { id: '2', content: 'Design landing page mockup', assignee: 'JD', type: 'task' },
        ],
    },
    'inProgress': {
        name: 'In Progress',
        items: [
            { id: '3', content: 'Implement authentication', assignee: 'PR', type: 'story' },
        ],
    },
    'done': {
        name: 'Done',
        items: [
            { id: '4', content: 'Set up repository', assignee: 'SM', type: 'task' },
        ],
    }
};

const ScrumBoardPage = () => {
    const [columns, setColumns] = useState(initialColumns);
    const [newTaskContent, setNewTaskContent] = useState('');
    const [activeCol, setActiveCol] = useState(null);

    const handleAddTask = (colId) => {
        if (!newTaskContent.trim()) return;
        const newItem = {
            id: Date.now().toString(),
            content: newTaskContent,
            assignee: 'ME',
            type: 'task'
        };
        setColumns({
            ...columns,
            [colId]: {
                ...columns[colId],
                items: [...columns[colId].items, newItem]
            }
        });
        setNewTaskContent('');
        setActiveCol(null);
    };

    const getTypeIcon = (type) => {
        if (type === 'story') {
            return <div className="type-icon story-icon"><svg viewBox="0 0 14 14" width="14" height="14"><rect width="14" height="14" rx="2" fill="#57D9A3" /><path d="M4 7h6v2H4z" fill="#fff" /></svg></div>;
        }
        return <div className="type-icon task-icon"><svg viewBox="0 0 14 14" width="14" height="14"><rect width="14" height="14" rx="2" fill="#4BCE97" /><path d="M5 9.5L3.5 8l-.7.7L5 10.9l6-6-.7-.7L5 9.5z" fill="#fff" /></svg></div>;
    };

    return (
        <div className="scrum-board-page">
            <div className="scrum-header">
                <div className="scrum-breadcrumbs">
                    <span>Projects</span> / <span>SOFTWARE DEV</span>
                </div>
                <h1>ANORYX Sprint 1</h1>
                <div className="scrum-toolbar">
                    <div className="search-bar">
                        <input type="text" placeholder="Search..." />
                    </div>
                    <div className="members">
                        <div className="member-avatar">SM</div>
                        <div className="member-avatar">JD</div>
                        <div className="member-avatar">PR</div>
                        <div className="member-avatar add-member">+</div>
                    </div>
                    <button className="btn-insight">Quick filters</button>
                    <button className="btn-complete-sprint">Complete sprint</button>
                </div>
            </div>

            <div className="board-container">
                {Object.entries(columns).map(([colId, column]) => (
                    <div className="board-column" key={colId}>
                        <div className="column-header">
                            <h3>{column.name.toUpperCase()}</h3>
                            <span className="item-count">{column.items.length}</span>
                        </div>
                        <div className="column-content">
                            {column.items.map((item) => (
                                <div className="board-card" key={item.id}>
                                    <p className="card-content">{item.content}</p>
                                    <div className="card-footer">
                                        <div className="card-tags">
                                            {getTypeIcon(item.type)}
                                            <span className="card-id">AN-{item.id.slice(-3)}</span>
                                        </div>
                                        <div className="card-assignee">{item.assignee}</div>
                                    </div>
                                </div>
                            ))}

                            {activeCol === colId ? (
                                <div className="add-card-form">
                                    <textarea
                                        autoFocus
                                        value={newTaskContent}
                                        onChange={(e) => setNewTaskContent(e.target.value)}
                                        placeholder="What needs to be done?"
                                        onKeyDown={(e) => {
                                            if (e.key === 'Enter' && !e.shiftKey) {
                                                e.preventDefault();
                                                handleAddTask(colId);
                                            }
                                        }}
                                    />
                                    <div className="add-card-actions">
                                        <button className="btn-save" onClick={() => handleAddTask(colId)}>Save</button>
                                        <button className="btn-cancel" onClick={() => setActiveCol(null)}>Cancel</button>
                                    </div>
                                </div>
                            ) : (
                                <button className="add-card-btn" onClick={() => setActiveCol(colId)}>
                                    + Create issue
                                </button>
                            )}
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
};

export default ScrumBoardPage;

import React, { useState, useEffect } from 'react';
import './AICostPredictionSection.css';

const AICostPredictionSection = () => {
    const [ticks, setTicks] = useState(0);

    useEffect(() => {
        const timer = setInterval(() => {
            setTicks((t) => (t > 50 ? 0 : t + 1));
        }, 400); // 400ms per tick
        return () => clearInterval(timer);
    }, []);

    const promptText = "Estimate the cost of scaling the backend infrastructure to handle 10x traffic, considering historical deployment data.";
    const typingLength = Math.min(promptText.length, Math.max(0, (ticks - 2) * 6));
    const displayedPrompt = promptText.substring(0, typingLength);

    const showCard1 = ticks >= 10;
    const card1Updates = Math.max(0, ticks - 11);

    const showCard2 = ticks >= 24;
    const card2Updates = Math.max(0, ticks - 25);

    return (
        <section className="ai-cost-prediction-section" id="ai-cost-prediction">
            <div className="ai-cost-prediction-container">
                <div className="ai-cost-prediction-left">
                    <h2 className="ai-section-title">AI-Based Cost Estimation Engine</h2>
                    <p className="ai-section-subtitle">
                        The AI-Based Cost Estimation Engine predicts project budgets using machine learning and historical data. It provides accurate cost forecasts and helps organizations make better financial decisions.
                    </p>
                </div>

                <div className="ai-cost-prediction-right">
                    <div className="animation-container">
                        {ticks >= 2 && (
                            <div className="prompt-bubble">
                                {displayedPrompt}
                                {typingLength < promptText.length && <span className="custom-cursor"></span>}
                            </div>
                        )}

                        {showCard1 && (
                            <div className="task-card active-gradient">
                                <div>
                                    <div className="card-title">Setup & Prediction Engine Active</div>
                                    <div className="card-subtitle">Preparing historical data, initializing models, and predicting requirements.</div>
                                </div>

                                <div>
                                    <div className="progress-updates-header">
                                        <div className="progress-updates-title">Progress updates</div>
                                        <div className="expand-all">Expand all &lt;</div>
                                    </div>
                                    <div className="updates-list">
                                        {card1Updates >= 1 && <div className="update-item"><span className="update-num">1</span> <div><strong>Historical Data Collection:</strong> Gather past project budgets, durations, and resource usage.</div></div>}
                                        {card1Updates >= 5 && <div className="update-item"><span className="update-num">2</span> <div><strong>Data Processing:</strong> Clean and structure data for analysis.</div></div>}
                                        {card1Updates >= 9 && <div className="update-item"><span className="update-num">3</span> <div><strong>Model Training:</strong> Train machine learning models to understand cost-driving factors.</div></div>}
                                        {card2Updates >= 1 && <div className="update-item"><span className="update-num">4</span> <div><strong>New Project Input:</strong> Input project scope, timeline, resources, and complexity.</div></div>}
                                        {card2Updates >= 5 && <div className="update-item"><span className="update-num">5</span> <div><strong>Cost Prediction:</strong> AI generates an estimated budget with accuracy metrics.</div></div>}
                                        {card2Updates >= 9 && <div className="update-item"><span className="update-num">6</span> <div><strong>Continuous Improvement:</strong> Model updates as more project data becomes available.</div></div>}
                                    </div>
                                </div>
                            </div>
                        )}

                        <div className="bottom-fade"></div>
                    </div>
                </div>
            </div>
        </section>
    );
};

export default AICostPredictionSection;

import React, { useEffect, useState, useRef } from 'react';
import './AIPromoVideo.css';

const AIPromoVideo = () => {
    const titleText = "AI-Driven Strategic Goal Alignment System";
    const words = titleText.split(" ");

    // Setup a small particle generator for neural network nodes and floating dust
    const [particles, setParticles] = useState([]);

    useEffect(() => {
        // Generate random particles
        const newParticles = Array.from({ length: 40 }).map((_, i) => ({
            id: i,
            x: Math.random() * 100,
            y: Math.random() * 100,
            size: Math.random() * 3 + 1,
            delay: Math.random() * 5,
            duration: Math.random() * 10 + 10,
        }));
        setParticles(newParticles);
    }, []);

    const renderAnimatedText = () => {
        let charIndex = 0;
        return words.map((word, wIdx) => (
            <span key={wIdx} className="word">
                {word.split('').map((char, cIdx) => {
                    const i = charIndex++;
                    return (
                        <span key={i} className="char" style={{ animationDelay: `${i * 0.04 + 0.5}s` }}>
                            {char}
                        </span>
                    );
                })}
                {wIdx < words.length - 1 && <span className="space">&nbsp;</span>}
            </span>
        ));
    };

    return (
        <section className="promo-video-container">
            <div className="video-frame">

                {/* Camera Push-in Wrapper */}
                <div className="camera-push-in">

                    {/* Background Elements */}
                    <div className="bg-dark-tech"></div>
                    <div className="bg-grid-lines"></div>

                    {/* Ambient Lighting Layers */}
                    <div className="ambient-blue-glow primary-glow"></div>
                    <div className="ambient-blue-glow accent-glow"></div>

                    {/* Neural Network Abstract SVG / CSS lines */}
                    <div className="neural-network">
                        {/* We use basic CSS rotating elements for the neural vibe */}
                        <div className="neural-line line-1"></div>
                        <div className="neural-line line-2"></div>
                        <div className="neural-line line-3"></div>
                    </div>

                    {/* Floating Particles Layers */}
                    <div className="particles-container">
                        {particles.map((p) => (
                            <div
                                key={p.id}
                                className="crypto-particle"
                                style={{
                                    left: `${p.x}%`,
                                    top: `${p.y}%`,
                                    width: `${p.size}px`,
                                    height: `${p.size}px`,
                                    animationDelay: `${p.delay}s`,
                                    animationDuration: `${p.duration}s`
                                }}
                            />
                        ))}
                    </div>

                    {/* Scene 1 Content */}
                    <div className="scene title-scene">
                        <div className="title-wrapper">
                            <h1 className="title-reveal">
                                {renderAnimatedText()}
                            </h1>
                            {/* The light sweep element that runs after title reveal */}
                            <div className="sweep-container">
                                <div className="light-sweep"></div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </section>
    );
};

export default AIPromoVideo;

import React, { useState, useEffect } from 'react';
import './AnimatedInputSection.css';

const AnimatedInputSection = () => {
    const [text, setText] = useState('');

    const sentences = [
        "How many roads must a man walk down before you call him a man?",
        "How many seas must a white dove sail before she sleeps in the sand?",
        "The answer, my friend, is blowin' in the wind"
    ];

    useEffect(() => {
        let currentSentenceIndex = 0;
        let currentCharIndex = 0;
        let isDeleting = false;
        let timeoutId;

        const handleType = () => {
            const currentSentence = sentences[currentSentenceIndex];

            // Update text based on whether we are deleting or typing
            if (isDeleting) {
                setText(currentSentence.substring(0, currentCharIndex - 1));
                currentCharIndex--;
            } else {
                setText(currentSentence.substring(0, currentCharIndex + 1));
                currentCharIndex++;
            }

            // Determine typing speed
            let typeSpeed = isDeleting ? 25 : 50;

            // Pause logics
            if (!isDeleting && currentCharIndex === currentSentence.length) {
                // Done typing the sentence, pause before deleting
                typeSpeed = 2500;
                isDeleting = true;
            } else if (isDeleting && currentCharIndex === 0) {
                // Done deleting the sentence, move to next and pause before starting
                isDeleting = false;
                currentSentenceIndex = (currentSentenceIndex + 1) % sentences.length;
                typeSpeed = 600;
            }

            // Schedule next tick
            timeoutId = setTimeout(handleType, typeSpeed);
        };

        // Start the loop
        timeoutId = setTimeout(handleType, 1000);

        // Cleanup
        return () => clearTimeout(timeoutId);
    }, []);

    return (
        <section className="animated-input-section">
            <div className="input-field-wrapper">
                <input
                    type="text"
                    className="animated-input"
                    aria-label="Ask us anything"
                    placeholder=" " /* The space is necessary for the :not(:placeholder-shown) CSS rule */
                />
                <span className="animated-placeholder">
                    {text}<span className="blink-caret"></span>
                </span>
            </div>
        </section>
    );
};

export default AnimatedInputSection;

import React, { useState, useEffect, useRef } from 'react';
import './AntigravityHero.css';

const AntigravityHero = () => {
    // Canvas Parallax Particle Engine
    const canvasRef = useRef(null);

    useEffect(() => {
        const canvas = canvasRef.current;
        const ctx = canvas.getContext('2d');
        let animationFrameId;

        let width, height;
        const particles = [];
        const particleCount = 600; // Dense starfield

        // Use mostly blues to match the provided screenshot
        const particleColors = ['#4285F4', '#8ab4f8', '#aecbfa', '#e8f0fe', '#5f6368'];

        // Base sphere layout
        const radiusBase = 600;

        for (let i = 0; i < particleCount; i++) {
            const phi = Math.acos(1 - 2 * (i + 0.5) / particleCount);
            const theta = Math.PI * (1 + Math.sqrt(5)) * i;

            const radiusOffset = (Math.random() * 400) - 100; // Deep spatial field
            const r = radiusBase + radiusOffset;

            const x = r * Math.sin(phi) * Math.cos(theta);
            const y = r * Math.cos(phi);
            const z = r * Math.sin(phi) * Math.sin(theta);

            // Vector along the latitude for dash effect
            const tx = -1 * Math.sin(theta);
            const ty = 0;
            const tz = Math.cos(theta);

            // Length of the lines/dashes
            const dashScale = 12 + Math.random() * 25;

            const px2 = x + tx * dashScale;
            const py2 = y + ty * dashScale;
            const pz2 = z + tz * dashScale;

            particles.push({
                x, y, z,
                px2, py2, pz2,
                color: particleColors[Math.floor(Math.random() * particleColors.length)],
                size: 1 + Math.random() * 1.5
            });
        }

        let targetRotX = 0;
        let targetRotY = 0;
        let currentRotX = 0;
        let currentRotY = 0;
        let globalSwirlAngle = 0;

        const resize = () => {
            width = window.innerWidth;
            height = window.innerHeight;
            canvas.width = width;
            canvas.height = height;
        };

        window.addEventListener('resize', resize);

        // Global mouse movement listener tracking
        const handleMouseMove = (e) => {
            const nx = (e.clientX / window.innerWidth) * 2 - 1;
            const ny = (e.clientY / window.innerHeight) * 2 - 1;

            targetRotY = nx * 0.45;
            targetRotX = -ny * 0.45;
        };

        window.addEventListener('mousemove', handleMouseMove);

        const animate = () => {
            ctx.clearRect(0, 0, width, height);

            // Slow constant rotation
            globalSwirlAngle += 0.001;

            currentRotX += (targetRotX - currentRotX) * 0.04;
            currentRotY += (targetRotY - currentRotY) * 0.04;

            const cx = width / 2;
            const cy = height / 2;

            const project = (px, py, pz) => {
                let rx = px * Math.cos(globalSwirlAngle) + pz * Math.sin(globalSwirlAngle);
                let ry = py;
                let rz = -px * Math.sin(globalSwirlAngle) + pz * Math.cos(globalSwirlAngle);

                let tx = rx * Math.cos(currentRotY) + rz * Math.sin(currentRotY);
                let trz = -rx * Math.sin(currentRotY) + rz * Math.cos(currentRotY);
                rx = tx;
                rz = trz;

                let try_val = ry * Math.cos(currentRotX) - rz * Math.sin(currentRotX);
                let trz2 = ry * Math.sin(currentRotX) + rz * Math.cos(currentRotX);
                ry = try_val;
                rz = trz2;

                const fov = 1000;
                const distance = 1400;

                const scale = fov / (fov + distance + rz);

                return {
                    scrX: cx + rx * scale,
                    scrY: cy + ry * scale,
                    scale: scale,
                    z: rz
                };
            };

            const projectedLines = particles.map(p => ({
                ...p,
                p1: project(p.x, p.y, p.z),
                p2: project(p.px2, p.py2, p.pz2)
            })).sort((a, b) => b.p1.z - a.p1.z); // Depth sorting

            projectedLines.forEach(line => {
                let opacity = 0.9;
                if (line.p1.z > 0) opacity = Math.max(0.05, 0.9 - (line.p1.z / 800));

                ctx.beginPath();
                ctx.moveTo(line.p1.scrX, line.p1.scrY);
                ctx.lineTo(line.p2.scrX, line.p2.scrY);
                ctx.strokeStyle = line.color;
                ctx.lineWidth = line.size * line.p1.scale;
                ctx.lineCap = 'round';
                ctx.globalAlpha = opacity;
                ctx.stroke();
            });

            ctx.globalAlpha = 1.0;
            animationFrameId = requestAnimationFrame(animate);
        };

        resize();
        animate();

        return () => {
            window.removeEventListener('resize', resize);
            window.removeEventListener('mousemove', handleMouseMove);
            cancelAnimationFrame(animationFrameId);
        };
    }, []);

    return (
        <section className="antigravity-hero dark-theme">
            {/* Dark Parallax Canvas Background */}
            <canvas ref={canvasRef} className="particles-canvas-bg"></canvas>

            <div className="hero-content-wrapper-left">
                <h1 className="hero-dark-title">
                    Download Google <br />
                    Antigravity for <br />
                    Windows <span className="typing-cursor is-blinking"></span>
                </h1>

                <div className="action-buttons-dark">
                    <button className="btn-light-capsule">
                        Download for x64
                    </button>
                    <button className="btn-dark-capsule">
                        Download for ARM64
                    </button>
                </div>
            </div>
        </section>
    );
};

export default AntigravityHero;

